PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE IF NOT EXISTS "d1_migrations"(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE pawns (
  id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL,
  pawn_name TEXT NOT NULL,
  arisen_name TEXT NOT NULL,
  platform TEXT NOT NULL,
  vocation TEXT NOT NULL,
  level INTEGER NOT NULL CHECK (level > 0),
  inclination TEXT NOT NULL,
  description TEXT NOT NULL,
  pawn_id TEXT NOT NULL,
  image_url TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending', 'approved', 'rejected')),
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now')), gender TEXT NOT NULL DEFAULT 'Unspecified' CHECK (gender IN ('Female', 'Male', 'Unspecified')), skills TEXT NOT NULL DEFAULT '', steam_url TEXT, switch_friend_id TEXT, psn_id TEXT, xbox_gamertag TEXT, activity_stars INTEGER NOT NULL DEFAULT 3 CHECK (activity_stars BETWEEN 1 AND 3), last_refreshed_at TEXT NOT NULL DEFAULT '1970-01-01 00:00:00', race TEXT NOT NULL DEFAULT 'Human' CHECK (race IN ('Human', 'Beastren')), image_urls TEXT NOT NULL DEFAULT '[]', thumbnail_url TEXT, weapon1 TEXT, weapon2 TEXT, head TEXT, body TEXT, legs TEXT, cloak TEXT, ring1 TEXT, ring2 TEXT, augment1 TEXT, augment2 TEXT, augment3 TEXT, augment4 TEXT, augment5 TEXT, augment6 TEXT, specialization TEXT,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE banned_emails (
  email TEXT PRIMARY KEY,
  reason TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE IF NOT EXISTS "users" (
  id TEXT PRIMARY KEY,
  email TEXT NOT NULL UNIQUE,
  password_hash TEXT NOT NULL,
  role TEXT NOT NULL DEFAULT 'user' CHECK (role IN ('user', 'moderator', 'admin')),
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  username TEXT,
  status TEXT NOT NULL DEFAULT 'active' CHECK (status IN ('active', 'banned'))
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_pawns_status_created_at ON pawns(status, created_at DESC);
CREATE INDEX idx_pawns_user_id ON pawns(user_id);
CREATE INDEX idx_pawns_filters ON pawns(platform, vocation, level);
CREATE INDEX idx_pawns_public_activity ON pawns(status, activity_stars, created_at DESC);
CREATE UNIQUE INDEX idx_users_username_lower ON users(lower(username));
CREATE INDEX idx_users_status ON users(status);
